        @CheckResult
        fun getLaunchType(intent: Intent): LaunchType {
            val action = intent.action
            return if (action == Intent.ACTION_SEND || Intent.ACTION_VIEW == action && isValidViewIntent(intent)) {
                val mimeType = intent.resolveMimeType()
                when {
                    mimeType?.startsWith("image/") == true -> LaunchType.IMAGE_IMPORT
                    isTextFile(intent, mimeType) -> LaunchType.TEXT_IMPORT
                    else -> LaunchType.FILE_IMPORT
                }
            } else if ("com.ichi2.anki.DO_SYNC" == action) {
                LaunchType.SYNC
            } else if (intent.hasExtra(ReminderService.EXTRA_DECK_ID)) {
                LaunchType.REVIEW
            } else if (action == CLIPBOARD_INTENT) {
                LaunchType.COPY_DEBUG_INFO
            } else {
                LaunchType.DEFAULT_START_APP_IF_NEW
            }
        }

        /**
         * Checks if the intent represents a text file (CSV/TSV) that should be imported
         * Uses MIME type detection and fallback to file extension checking
         */
        private fun isTextFile(intent: Intent, mimeType: String?): Boolean {
            // Check standard MIME types for CSV/TSV files
            when (mimeType) {
                "text/tab-separated-values",
                "text/comma-separated-values",
                "text/csv",
                "application/csv",
                "text/tsv" -> return true
            }

            // Fallback: check file extension when MIME type is generic or null
            // This handles cases where MIME type detection fails or returns "text/plain", "*/*", etc.
            if (mimeType == null || mimeType == "text/plain" || mimeType == "*/*" || mimeType == "application/octet-stream") {
                val dataUri = intent.data ?: intent.clipData?.getItemAt(0)?.uri
                if (dataUri != null) {
                    val uriString = dataUri.toString().lowercase()
                    return uriString.endsWith(".csv") || uriString.endsWith(".tsv")
                }

                // Also check filename from clipData description
                intent.clipData?.description?.label?.toString()?.let { filename ->
                    val lowerFilename = filename.lowercase()
                    return lowerFilename.endsWith(".csv") || lowerFilename.endsWith(".tsv")
                }
            }

            return false
        }"}

